<!-- 功能说明
管理端入口页面，支持管理员 / 客服账号密码登录，包含密码显示 / 隐藏、表单校验（账号密码必填）、登录状态存储，
核心对接管理端登录接口，登录后根据角色跳转对应后台首页。 -->
<template>
  <view class="admin-login-container">
    <view class="login-form">
      <image src="/static/images/login-logo.png" class="logo"></image>
      <text class="login-title">管理后台登录</text>
      
      <!-- 账号输入 -->
      <view class="form-item">
        <image src="/static/images/icon-account.png" class="form-icon"></image>
        <input 
          class="form-input" 
          v-model="loginForm.username" 
          placeholder="请输入账号"
          maxlength="20"
        ></input>
      </view>
      
      <!-- 密码输入 -->
      <view class="form-item">
        <image src="/static/images/icon-password.png" class="form-icon"></image>
        <input 
          class="form-input" 
          v-model="loginForm.password" 
          placeholder="请输入密码"
          :type="showPassword ? 'text' : 'password'"
          maxlength="20"
        ></input>
        <image 
          :src="showPassword ? '/static/images/icon-hide.png' : '/static/images/icon-show.png'" 
          class="eye-icon"
          @click="togglePassword"
        ></image>
      </view>
      
      <!-- 登录按钮 -->
      <button 
        class="login-btn" 
        @click="submitLogin"
        :disabled="isSubmitting"
      >
        <text v-if="isSubmitting">登录中...</text>
        <text v-else>登录</text>
      </button>
      
      <!-- 忘记密码 -->
      <text class="forgot-password" @click="goToForgotPassword">忘记密码？</text>
    </view>
  </view>
</template>

<script setup>
import { ref } from 'vue';
import { onLoad } from '@dcloudio/uni-app';
import { useUserStore } from '@/store/modules/userStore';
import request from '@/utils/request';

// 状态管理
const userStore = useUserStore();

// 页面数据
const loginForm = ref({
  username: '',
  password: ''
});
const showPassword = ref(false); // 密码显示状态
const isSubmitting = ref(false); // 登录状态

// 切换密码显示/隐藏
const togglePassword = () => {
  showPassword.value = !showPassword.value;
};

// 提交登录
const submitLogin = async () => {
  // 表单校验
  if (!loginForm.value.username.trim()) {
    uni.showToast({ title: '请输入账号', icon: 'none' });
    return;
  }
  if (!loginForm.value.password.trim()) {
    uni.showToast({ title: '请输入密码', icon: 'none' });
    return;
  }

  isSubmitting.value = true;
  uni.showLoading({ title: '正在登录...', mask: true });

  try {
    const res = await request({
      url: '/api/admin/login',
      method: 'POST',
      data: {
        username: loginForm.value.username.trim(),
        password: loginForm.value.password.trim()
      }
    });

    if (res.success) {
      const { token, userInfo } = res.data;
      // 存储登录状态（持久化）
      userStore.setToken(token);
      userStore.setUserInfo(userInfo);
      uni.setStorageSync('adminUser', userInfo);
      
      uni.hideLoading();
      uni.showToast({ 
        title: '登录成功',
        icon: 'success',
        duration: 1500
      });

      // 延迟跳转，确保用户看到提示
      setTimeout(() => {
        uni.switchTab({ url: '/pages/admin/index/index' });
      }, 1500);
    } else {
      uni.hideLoading();
      uni.showToast({ title: res.message || '登录失败', icon: 'none' });
    }
  } catch (error) {
    uni.hideLoading();
    uni.showToast({ title: '网络异常，登录失败', icon: 'none' });
  } finally {
    isSubmitting.value = false;
  }
};

// 跳转忘记密码页
const goToForgotPassword = () => {
  uni.navigateTo({ url: '/pages/admin/forgot-password' });
};

// 页面加载时校验是否已登录
onLoad(() => {
  const adminUser = uni.getStorageSync('adminUser');
  if (adminUser && userStore.token) {
    uni.switchTab({ url: '/pages/admin/index/index' });
  }
});
</script>

